import{_ as a,o,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"算随电动：数据中心虚拟电厂首单交易的商业逻辑","description":"国内首次大型数据中心通过虚拟电厂参与电力现货市场交易 — 算电协同从概念到落地的标杆案例拆解","frontmatter":{"title":"算随电动：数据中心虚拟电厂首单交易的商业逻辑","description":"国内首次大型数据中心通过虚拟电厂参与电力现货市场交易 — 算电协同从概念到落地的标杆案例拆解"},"headers":[],"relativePath":"算电协同/数据中心虚拟电厂首单交易的商业逻辑.md","filePath":"算电协同/数据中心虚拟电厂首单交易的商业逻辑.md","lastUpdated":1781978464000}'),e={name:"算电协同/数据中心虚拟电厂首单交易的商业逻辑.md"};function h(n,t,l,i,u,s){return o(),d("div",null,[...t[0]||(t[0]=[r('<h2 id="一、一笔不起眼但重要的交易" tabindex="-1">一、一笔不起眼但重要的交易 <a class="header-anchor" href="#一、一笔不起眼但重要的交易" aria-label="Permalink to &quot;一、一笔不起眼但重要的交易&quot;">​</a></h2><p>2026年5月14日，广东电力现货市场的交易系统里，多了三个不太一样的参与者。</p><p>中国联通韶关数据中心、中国移动广州数据中心、中国移动湛江数据中心——三个大型数据中心集群，依托广东电网能源投资有限公司&quot;粤能投虚拟电厂运营平台&quot;，正式以虚拟电厂身份参与电力现货市场电能量交易与结算。<strong>这是国内首次大型数据中心通过虚拟电厂参与电力现货市场交易。</strong>（来源：中国能源新闻网，2026年5月18日）</p><p>这笔交易的具体操作并不复杂：</p><table tabindex="0"><thead><tr><th>时段</th><th>电价特征</th><th>算力调度指令</th><th>商业效果</th></tr></thead><tbody><tr><td>10:00-14:00</td><td>低谷电价</td><td>调增算力任务，满负荷运行</td><td>消纳低成本电力</td></tr><tr><td>16:00-20:00</td><td>高峰电价</td><td>调减非紧急任务，压降负荷</td><td>避免高价购电，富余容量并网获利</td></tr></tbody></table><p>虚拟电厂平台根据广东电力现货日前价格预测，分钟级调度非紧急算力任务的&quot;作息&quot;——低谷时开足马力，高峰时主动让路。过去，算力任务的优先级只看数据队列的先来后到；现在，电价成了调度决策的变量之一。（来源：科技日报，2026年5月16日）</p><h2 id="二、从-电随算动-到-算随电动" tabindex="-1">二、从&quot;电随算动&quot;到&quot;算随电动&quot; <a class="header-anchor" href="#二、从-电随算动-到-算随电动" aria-label="Permalink to &quot;二、从&quot;电随算动&quot;到&quot;算随电动&quot;&quot;">​</a></h2><p>这笔交易背后有一个概念的翻转。</p><p>传统模式下，数据中心是&quot;刚性用电巨兽&quot;——用电量由算力需求决定，不可调节、不可中断。电网只能被动满足其用电需求，这一模式被称为**&quot;电随算动&quot;**：电力系统被动适配算力负荷。</p><p>&quot;算随电动&quot;则完全反转了这个逻辑：数据中心根据电价信号主动调节算力负荷，算力跟着电力走。非紧急任务在电价低时多跑、电价高时少跑，数据中心从被动的电力消费者，变为电网的可调负荷主体。（来源：36氪，2026年5月20日）</p><p>这种转变的经济价值是双向的：</p><p><strong>对数据中心</strong>：电费占运营成本40%-60%，通过虚拟电厂平台参与现货交易，可降低用电成本10%-25%，同时获得辅助服务收益。（来源：南方电网/券商测算数据）</p><p><strong>对电网</strong>：数据中心成为柔性调节资源，削峰填谷能力相当于一座中型调峰电厂，提升新能源消纳能力。</p><h2 id="三、虚拟电厂平台-算电协同时代的-卖水人" tabindex="-1">三、虚拟电厂平台：算电协同时代的&quot;卖水人&quot; <a class="header-anchor" href="#三、虚拟电厂平台-算电协同时代的-卖水人" aria-label="Permalink to &quot;三、虚拟电厂平台：算电协同时代的&quot;卖水人&quot;&quot;">​</a></h2><p>参与交易的主体是联通和移动的数据中心，但让这件事跑通的核心角色是中间的虚拟电厂平台。</p><p>&quot;粤能投虚拟电厂运营平台&quot;由东方电子开发建设，是国内规模最大的市场化运营虚拟电厂。它的角色像一个&quot;电力版聚合平台&quot;——把分散的数据中心负荷聚合起来，统一参与电力市场交易。（来源：东方电子官网；深交所互动易）</p><h3 id="虚拟电厂的收益模式" tabindex="-1">虚拟电厂的收益模式 <a class="header-anchor" href="#虚拟电厂的收益模式" aria-label="Permalink to &quot;虚拟电厂的收益模式&quot;">​</a></h3><p>虚拟电厂平台的收入来源正在从单一的政策补贴向多元化演进：</p><table tabindex="0"><thead><tr><th>收益类型</th><th>当前占比</th><th>稳定性</th><th>增长前景</th></tr></thead><tbody><tr><td>峰谷价差套利</td><td>低（仅少数案例）</td><td>中等</td><td>随现货市场扩大而增长</td></tr><tr><td>辅助服务（调峰等）</td><td>中等</td><td>较高</td><td>政策驱动，稳定增长</td></tr><tr><td>需求响应补贴</td><td>高（大部分VPP）</td><td>低（依赖财政）</td><td>远期将退出</td></tr><tr><td>容量租赁</td><td>极低</td><td>需市场机制</td><td>远期潜力大</td></tr></tbody></table><p>当前大部分虚拟电厂盈利仍依赖需求响应补贴，真正通过现货价差获利的案例极少。<strong>商业模式尚未完全跑通，但方向已经明确。</strong>（来源：21世纪经济报道，2026年5月31日）</p><h2 id="四、竞争格局与pe视角" tabindex="-1">四、竞争格局与PE视角 <a class="header-anchor" href="#四、竞争格局与pe视角" aria-label="Permalink to &quot;四、竞争格局与PE视角&quot;">​</a></h2><h3 id="虚拟电厂平台主要玩家" tabindex="-1">虚拟电厂平台主要玩家 <a class="header-anchor" href="#虚拟电厂平台主要玩家" aria-label="Permalink to &quot;虚拟电厂平台主要玩家&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>核心定位</th><th>关键优势</th><th>PE适配度</th></tr></thead><tbody><tr><td><strong>东方电子</strong>（000682）</td><td>全链条集成商</td><td>粤能投平台开发商，园区/聚合商/城市三级布局</td><td>上市公司，可作为赛道风向标</td></tr><tr><td><strong>国电南瑞</strong>（600406）</td><td>电网侧优势</td><td>全国VPP市占率&gt;50%，国网体系</td><td>体量太大，PE空间有限</td></tr><tr><td><strong>恒华科技</strong>（300365）</td><td>软件服务商</td><td>服务场景从工业拓展至数据中心</td><td>关注其客户拓展速度</td></tr><tr><td><strong>朗新科技</strong>（300682）</td><td>能源AI公司</td><td>能源服务+AI运营</td><td>商业模式独特，需验证</td></tr></tbody></table><p><strong>PE视角的关键判断：</strong></p><p>虚拟电厂平台的竞争壁垒不在软件本身——纯软件平台可复制性强——而在&quot;对下懂资源改造、对上懂电网调度、中间懂市场交易&quot;的全链条能力。东方电子在广东的成功，核心不是技术领先，而是过去十年在电网侧的积累。</p><p>对于一级市场投资人，值得关注的不是上述上市公司（已上市、估值透明），而是<strong>数据中心专用虚拟电厂平台</strong>和<strong>负荷侧资源聚合商</strong>——这两个细分方向目前以民营创业公司为主，尚处于早期阶段。</p><h2 id="五、规模化落地的三道坎" tabindex="-1">五、规模化落地的三道坎 <a class="header-anchor" href="#五、规模化落地的三道坎" aria-label="Permalink to &quot;五、规模化落地的三道坎&quot;">​</a></h2><p>首单落地验证了技术可行性，但从个案到产业化，还有三个关键问题需要解决。</p><h3 id="_1-现货市场覆盖面不足" tabindex="-1">① 现货市场覆盖面不足 <a class="header-anchor" href="#_1-现货市场覆盖面不足" aria-label="Permalink to &quot;① 现货市场覆盖面不足&quot;">​</a></h3><p>这笔交易能在广东落地，前提是广东电力现货市场已正式运行（2024年6月）。目前全国正式运行的省份仅广东一家，2026年目标是一半以上省份正式运行。（来源：发改委394号文）</p><p>没有现货市场→没有价格信号→虚拟电厂无法套利→数据中心没有参与动力。</p><h3 id="_2-算力可调比例有限" tabindex="-1">② 算力可调比例有限 <a class="header-anchor" href="#_2-算力可调比例有限" aria-label="Permalink to &quot;② 算力可调比例有限&quot;">​</a></h3><p>并非所有算力都能调度。在线推理、实时交易等延迟敏感业务不可调度。只有非实时算力（AI批处理训练、数据备份、离线分析）才有调度空间。不同类型的数据中心，可调负荷比例从10%到40%不等。</p><p>中国联通粤港澳大湾区创新研究院副院长马晨坦言：&quot;有效解决数据中心使用电力市场门槛高、技术复杂的难题，但最大的难点还是找到可以调节的算力负荷。&quot;（来源：中国能源新闻网，2026年5月18日）</p><h3 id="_3-商业模式成熟度不足" tabindex="-1">③ 商业模式成熟度不足 <a class="header-anchor" href="#_3-商业模式成熟度不足" aria-label="Permalink to &quot;③ 商业模式成熟度不足&quot;">​</a></h3><p>广东电网能源投资有限公司市场交易事业部总经理朱振海表示，参与交易的数据中心收益来自两方面：现货价差收益和辅助服务收益。但这份收益能否覆盖改造成本、形成稳定预期，目前还没有足够的数据支撑。（来源：第一财经，2026年6月2日）</p><h2 id="六、核心判断" tabindex="-1">六、核心判断 <a class="header-anchor" href="#六、核心判断" aria-label="Permalink to &quot;六、核心判断&quot;">​</a></h2><p><strong>第一，算随电动首单交易是算电协同从政策文件走向商业实操的标志性事件。</strong> 它的意义不在交易金额大小，而在于跑通了&quot;政策→平台→市场→收益&quot;的完整闭环。</p><p><strong>第二，虚拟电厂平台是算电协同时代确定性最高的环节。</strong> 数据中心的&quot;算随电动&quot;改造是一个天花板极高的市场——全国数千座大型数据中心，每一座都需要接入电力市场。连接两端的&quot;管道&quot;具有天然的规模效应和客户黏性。</p><p><strong>第三，2026年下半年是关键观察窗口。</strong> 如果广东模式在3-6个月内被第二个省份复制，说明规模化启动；如果到年底仍只有广东一家，则说明标准化阻力超出预期。</p><hr><h2 id="数据来源" tabindex="-1">数据来源 <a class="header-anchor" href="#数据来源" aria-label="Permalink to &quot;数据来源&quot;">​</a></h2><ol><li>中国能源新闻网，《国内首笔！数据中心接入虚拟电厂参与电力现货交易》，2026年5月18日</li><li>科技日报/中国科技网，2026年5月16日</li><li>36氪，《历史性反转，从&quot;电随算动&quot;到&quot;算随电动&quot;》，2026年5月20日</li><li>21世纪经济报道，《首单&quot;算随电动&quot;落地广东，虚拟电厂迎超级风口》，2026年5月20日</li><li>21世纪经济报道，《&quot;算电协同&quot;电力现货首单交割，虚拟电厂千亿赛道难点待解》，2026年5月31日</li><li>第一财经，《&quot;算电协同&quot;电力现货交易开启，互联网大厂会跟吗？》，2026年6月2日</li><li>东方电子官网、深交所互动易</li><li>国家发改委、国家能源局政策文件</li></ol><hr><p><em>本文仅为投资研究视角分享，不构成任何投资建议。</em></p>',45)])])}const _=a(e,[["render",h]]);export{p as __pageData,_ as default};
